import 'dart:convert';import 'package:http/http.dart' as http;class DeliveryApi{DeliveryApi({this.baseUrl='http://10.0.2.2:4000/api'});final String baseUrl;String? token;Future<dynamic> call(String path,{String method='GET',Object? body})async{final r=await http.Request(method,Uri.parse('$baseUrl$path'))..headers.addAll({'Content-Type':'application/json',if(token!=null)'Authorization':'Bearer $token'});if(body!=null)r.body=jsonEncode(body);final response=await http.Response.fromStream(await r.send());final data=jsonDecode(response.body);if(response.statusCode>=400)throw Exception(data['message']);return data['data'];}}final deliveryApi=DeliveryApi();
